import{_ as o,C as c,o as t,c as n,H as i,Q as a}from"./chunks/framework.9e8bdea8.js";const v=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"runtime-env/node/npm/publish.md","filePath":"runtime-env/node/npm/publish.md"}'),d={name:"runtime-env/node/npm/publish.md"},l=a('<p>如果你想发布一个 NPM 包，按照以下步骤操作：</p><ol><li>运行 <code>npm version patch</code> 来更新包的版本号。</li><li>运行 <code>npm login</code> 登陆你的 NPM 账号。</li><li>运行 <code>npm publish</code> 来发布包。</li></ol><div class="danger custom-block"><p class="custom-block-title">patch （修补程序）、 minor （次要版本）和 major （主要版本）有什么区别？</p><ul><li><code>patch</code> ：修复 Bug 、或小改动时用，<code>例如, 1.0.0 -&gt; 1.0.1</code>。</li><li><code>minor</code> ：添加新功能，但是保持向后兼容时用，<code>例如, 1.0.0 -&gt; 1.1.0</code>。</li><li><code>major</code> ：做了不向后兼容的更改，或者是重大的更新时用。<code>例如, 1.0.0 -&gt; 2.0.0</code>。</li></ul><p>根据语义化版本控制（Semantic Versioning）规范，更新版本号时应该遵循以上规则，以便其他开发者能够清楚地了解新版本对应的改动。</p></div>',3);function s(p,r,m,_,u,h){const e=c("PageHeader");return t(),n("div",null,[i(e,{content:"如何发布一个 NPM 包？"}),l])}const P=o(d,[["render",s]]);export{v as __pageData,P as default};
